CREATE TABLE IF NOT EXISTS `api_builder_samples` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '自增主键',
  `uuid` varchar(128) NOT NULL COMMENT '样例唯一标识',
  `title` varchar(120) NOT NULL COMMENT '样例标题',
  `description` text NOT NULL COMMENT '样例说明',
  `method` varchar(16) NOT NULL COMMENT 'HTTP 请求方法',
  `api_json` json NOT NULL COMMENT 'API DSL 定义 JSON',
  `status` varchar(32) NOT NULL DEFAULT 'active' COMMENT '样例状态',
  `sort_order` int NOT NULL DEFAULT 0 COMMENT '排序值',
  `created_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) COMMENT '创建时间',
  `updated_at` timestamp(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6) COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_api_builder_samples_uuid` (`uuid`),
  KEY `idx_api_builder_samples_status_sort` (`status`, `sort_order`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci COMMENT='API Builder 内置样例表';

INSERT INTO `api_builder_samples` (`uuid`, `title`, `description`, `method`, `api_json`, `status`, `sort_order`) VALUES
  ('login', '登录接口', '读取用户、校验密码、写入 Session。', 'POST', '{"uuid":"login_employees","alias":"employees 登录接口","method":"POST","request":{"body":[{"key":"email","processors":["trim","is_not_null","email_check",{"processor":"max","param":[255]}]},{"key":"password","processors":["is_not_null"]}]},"blocks":[{"uuid":"starter","nextBlock":"read_user"},{"uuid":"read_user","alias":"按邮箱读取用户","functionName":"read","inputs":{"datasource":"Mokelay","table":"employees","fields":["id","enterprise_uuid","name","email","plan","password_hash"],"conditions":[{"group":false,"fieldName":"email","fieldValue":{"template":"{{request.body.email}}"},"conditionType":"EQ"}]},"outputs":[{"key":"data","processors":["is_not_null"]}],"nextBlock":"check_user_password"},{"uuid":"check_user_password","alias":"校验密码","functionName":"if_controller","type":"controller","inputs":{"value":{"template":"{{blocks[''read_user''].outputs.data.password_hash}}","processors":[{"processor":"hash_check","param":[{"template":"{{request.body.password}}"}]}]}},"nodes":[{"uuid":"password_true_node","alias":"校验通过","value":true,"nextBlock":"read_enterprise"},{"uuid":"password_false_node","alias":"校验失败","value":false,"nextBlock":null}]},{"uuid":"read_enterprise","alias":"读取企业","functionName":"read","inputs":{"datasource":"Mokelay","table":"enterprise","fields":["uuid","name"],"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{blocks[''read_user''].outputs.data.enterprise_uuid}}"},"conditionType":"EQ"}]},"outputs":[{"key":"data","processors":["is_not_null"]}],"nextBlock":"set_user_session"},{"uuid":"set_user_session","alias":"写入用户 Session","functionName":"addSession","inputs":{"key":"user","value":{"id":{"template":"{{blocks[''read_user''].outputs.data.id}}"},"enterprise_uuid":{"template":"{{blocks[''read_user''].outputs.data.enterprise_uuid}}"},"name":{"template":"{{blocks[''read_user''].outputs.data.name}}"},"email":{"template":"{{blocks[''read_user''].outputs.data.email}}"},"plan":{"template":"{{blocks[''read_user''].outputs.data.plan}}"},"enterprise_name":{"template":"{{blocks[''read_enterprise''].outputs.data.name}}"}}},"outputs":[],"nextBlock":null}],"responses":{"set_user_session":{"user":{"id":{"template":"{{blocks[''read_user''].outputs.data.id}}"},"enterprise_uuid":{"template":"{{blocks[''read_user''].outputs.data.enterprise_uuid}}"},"name":{"template":"{{blocks[''read_user''].outputs.data.name}}"},"email":{"template":"{{blocks[''read_user''].outputs.data.email}}"},"plan":{"template":"{{blocks[''read_user''].outputs.data.plan}}"},"enterprise_name":{"template":"{{blocks[''read_enterprise''].outputs.data.name}}"}}},"password_false_node":{"user":null}}}', 'active', 1),
  ('register', '注册接口', '校验重复邮箱、创建用户、写入 Session。', 'POST', '{"uuid":"register_employees","alias":"employees 注册接口","method":"POST","request":{"body":[{"key":"enterprise_name","processors":["trim","is_not_null",{"processor":"max","param":[120]}]},{"key":"name","processors":["trim","is_not_null",{"processor":"max","param":[128]}]},{"key":"email","processors":["trim","is_not_null","email_check",{"processor":"max","param":[255]}]},{"key":"password","processors":["is_not_null",{"processor":"min","param":[8]},{"processor":"max","param":[128]}]}]},"blocks":[{"uuid":"starter","nextBlock":"check_duplicate"},{"uuid":"check_duplicate","alias":"校验邮箱重复","functionName":"count","inputs":{"datasource":"Mokelay","table":"employees","conditions":[{"group":false,"fieldName":"email","fieldValue":{"template":"{{request.body.email}}"},"conditionType":"EQ"}]},"outputs":[{"key":"total","processors":[{"processor":"eq","param":[0]}]}],"nextBlock":"create_enterprise"},{"uuid":"create_enterprise","alias":"创建企业","functionName":"create","inputs":{"datasource":"Mokelay","table":"enterprise","idField":"uuid","fields":{"name":{"template":"{{request.body.enterprise_name}}"}}},"outputs":["uuid"],"nextBlock":"read_enterprise"},{"uuid":"read_enterprise","alias":"读取企业","functionName":"read","inputs":{"datasource":"Mokelay","table":"enterprise","fields":["uuid","name"],"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{blocks[''create_enterprise''].outputs.uuid}}"},"conditionType":"EQ"}]},"outputs":["data"],"nextBlock":"create_record"},{"uuid":"create_record","alias":"创建用户","functionName":"create","inputs":{"datasource":"Mokelay","table":"employees","idField":"id","fields":{"enterprise_uuid":{"template":"{{blocks[''create_enterprise''].outputs.uuid}}"},"name":{"template":"{{request.body.name}}"},"email":{"template":"{{request.body.email}}"},"password_hash":{"template":"{{request.body.password}}","processors":["hash_make"]}}},"outputs":["uuid"],"nextBlock":"read_record"},{"uuid":"read_record","alias":"读取新用户","functionName":"read","inputs":{"datasource":"Mokelay","table":"employees","fields":["id","enterprise_uuid","name","email","plan"],"conditions":[{"group":false,"fieldName":"id","fieldValue":{"template":"{{blocks[''create_record''].outputs.uuid}}"},"conditionType":"EQ"}]},"outputs":["data"],"nextBlock":"set_user_session"},{"uuid":"set_user_session","alias":"写入用户 Session","functionName":"addSession","inputs":{"key":"user","value":{"id":{"template":"{{blocks[''read_record''].outputs.data.id}}"},"enterprise_uuid":{"template":"{{blocks[''read_record''].outputs.data.enterprise_uuid}}"},"name":{"template":"{{blocks[''read_record''].outputs.data.name}}"},"email":{"template":"{{blocks[''read_record''].outputs.data.email}}"},"plan":{"template":"{{blocks[''read_record''].outputs.data.plan}}"},"enterprise_name":{"template":"{{blocks[''read_enterprise''].outputs.data.name}}"}}},"outputs":[],"nextBlock":null}],"response":{"user":{"id":{"template":"{{blocks[''read_record''].outputs.data.id}}"},"enterprise_uuid":{"template":"{{blocks[''read_record''].outputs.data.enterprise_uuid}}"},"name":{"template":"{{blocks[''read_record''].outputs.data.name}}"},"email":{"template":"{{blocks[''read_record''].outputs.data.email}}"},"plan":{"template":"{{blocks[''read_record''].outputs.data.plan}}"},"enterprise_name":{"template":"{{blocks[''read_enterprise''].outputs.data.name}}"}}}}', 'active', 2),
  ('me', '当前用户', '读取 Session 并返回 loggedIn。', 'GET', '{"uuid":"me","alias":"当前用户接口","method":"GET","blocks":[{"uuid":"starter","nextBlock":"read_user_session"},{"uuid":"read_user_session","alias":"读取用户 Session","functionName":"readSession","inputs":{"key":"user"},"outputs":["value"],"nextBlock":null}],"response":{"user":{"template":"{{blocks[''read_user_session''].outputs.value}}"},"loggedIn":{"template":"{{blocks[''read_user_session''].outputs.value}}","processors":["not_null"]}}}', 'active', 3),
  ('logout', '退出登录', '清除 Session 并返回 success。', 'POST', '{"uuid":"logout","alias":"退出登录接口","method":"POST","blocks":[{"uuid":"starter","nextBlock":"clear_user_session"},{"uuid":"clear_user_session","alias":"清除用户 Session","functionName":"removeSession","inputs":{"key":"user"},"outputs":[],"nextBlock":null}],"response":{"success":true}}', 'active', 4),
  ('list-pages', '页面分页', '分页查询 pages 并返回 pagination。', 'GET', '{"uuid":"page_pages","alias":"pages 分页列表","method":"GET","request":{"query":["page","pageSize"]},"blocks":[{"uuid":"starter","nextBlock":"page_records"},{"uuid":"page_records","alias":"分页查询","functionName":"page","inputs":{"datasource":"Mokelay","table":"pages","fields":["uuid","name","blocks","created_at","updated_at"],"page":{"template":"{{request.query.page}}"},"pageSize":{"template":"{{request.query.pageSize}}"},"orderBy":[{"fieldName":"uuid","direction":"DESC"}]},"outputs":["datas","total","totalPages","page","pageSize","hasPreviousPage","hasNextPage"],"nextBlock":null}],"response":{"datas":{"template":"{{blocks[''page_records''].outputs.datas}}"},"pagination":{"page":{"template":"{{blocks[''page_records''].outputs.page}}"},"pageSize":{"template":"{{blocks[''page_records''].outputs.pageSize}}"},"total":{"template":"{{blocks[''page_records''].outputs.total}}"},"totalPages":{"template":"{{blocks[''page_records''].outputs.totalPages}}"},"hasPreviousPage":{"template":"{{blocks[''page_records''].outputs.hasPreviousPage}}"},"hasNextPage":{"template":"{{blocks[''page_records''].outputs.hasNextPage}}"}}}}', 'active', 5),
  ('read-page', '页面详情', '按 uuid 查询单个页面。', 'GET', '{"uuid":"read_pages_by_uuid","alias":"pages 详情查询","method":"GET","request":{"query":[{"key":"uuid","processors":["is_not_null"]}]},"blocks":[{"uuid":"starter","nextBlock":"read_record"},{"uuid":"read_record","alias":"读取详情","functionName":"read","inputs":{"datasource":"Mokelay","table":"pages","fields":["uuid","name","blocks","created_at","updated_at"],"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{request.query.uuid}}"},"conditionType":"EQ"}]},"outputs":["data"],"nextBlock":null}],"response":{"data":{"template":"{{blocks[''read_record''].outputs.data}}"}}}', 'active', 6),
  ('create-page', '创建页面', '创建记录后读取完整数据。', 'POST', '{"uuid":"create_pages","alias":"创建 pages","method":"POST","request":{"body":[{"key":"name","processors":["is_not_null"]},{"key":"blocks","processors":["is_not_null"]}]},"blocks":[{"uuid":"starter","nextBlock":"create_record"},{"uuid":"create_record","alias":"创建记录","functionName":"create","inputs":{"datasource":"Mokelay","table":"pages","idField":"uuid","fields":{"name":{"template":"{{request.body.name}}"},"blocks":{"template":"{{request.body.blocks}}"}}},"outputs":["uuid"],"nextBlock":"read_record"},{"uuid":"read_record","alias":"读取新记录","functionName":"read","inputs":{"datasource":"Mokelay","table":"pages","fields":["uuid","name","blocks","created_at","updated_at"],"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{blocks[''create_record''].outputs.uuid}}"},"conditionType":"EQ"}]},"outputs":["data"],"nextBlock":null}],"response":{"uuid":{"template":"{{blocks[''create_record''].outputs.uuid}}"},"data":{"template":"{{blocks[''read_record''].outputs.data}}"}}}', 'active', 7),
  ('update-page', '更新页面', '更新 blocks 后读取最新页面。', 'POST', '{"uuid":"update_pages_by_uuid","alias":"更新 pages","method":"POST","request":{"query":[{"key":"uuid","processors":["is_not_null"]}],"body":[{"key":"name","processors":["is_not_null"]},{"key":"blocks","processors":["is_not_null"]}]},"blocks":[{"uuid":"starter","nextBlock":"update_record"},{"uuid":"update_record","alias":"更新记录","functionName":"update","inputs":{"datasource":"Mokelay","table":"pages","fields":{"name":{"template":"{{request.body.name}}"},"blocks":{"template":"{{request.body.blocks}}"}},"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{request.query.uuid}}"},"conditionType":"EQ"}]},"outputs":["affected"],"nextBlock":"read_record"},{"uuid":"read_record","alias":"读取最新记录","functionName":"read","inputs":{"datasource":"Mokelay","table":"pages","fields":["uuid","name","blocks","created_at","updated_at"],"conditions":[{"group":false,"fieldName":"uuid","fieldValue":{"template":"{{request.query.uuid}}"},"conditionType":"EQ"}]},"outputs":["data"],"nextBlock":null}],"response":{"affected":{"template":"{{blocks[''update_record''].outputs.affected}}"},"data":{"template":"{{blocks[''read_record''].outputs.data}}"}}}', 'active', 8),
  ('delete-wallet', '删除钱包', '按 id 删除钱包并返回 affected。', 'POST', '{"uuid":"delete_wallets_by_id","alias":"删除 wallets","method":"POST","request":{"body":[{"key":"id","processors":["is_not_null"]}]},"blocks":[{"uuid":"starter","nextBlock":"delete_record"},{"uuid":"delete_record","alias":"删除记录","functionName":"delete","inputs":{"datasource":"BingX","table":"wallets","conditions":[{"group":false,"fieldName":"id","fieldValue":{"template":"{{request.body.id}}"},"conditionType":"EQ"}]},"outputs":["affected"],"nextBlock":null}],"response":{"affected":{"template":"{{blocks[''delete_record''].outputs.affected}}"}}}', 'active', 9),
  ('count-wallets', '统计钱包', '统计 BingX wallets 记录数量。', 'GET', '{"uuid":"count_wallets","alias":"统计 wallets","method":"GET","blocks":[{"uuid":"starter","nextBlock":"count_records"},{"uuid":"count_records","alias":"统计数量","functionName":"count","inputs":{"datasource":"BingX","table":"wallets","conditions":[]},"outputs":["total"],"nextBlock":null}],"response":{"total":{"template":"{{blocks[''count_records''].outputs.total}}"}}}', 'active', 10)
ON DUPLICATE KEY UPDATE
  `title` = VALUES(`title`),
  `description` = VALUES(`description`),
  `method` = VALUES(`method`),
  `api_json` = VALUES(`api_json`),
  `status` = VALUES(`status`),
  `sort_order` = VALUES(`sort_order`),
  `updated_at` = CURRENT_TIMESTAMP(6);
